#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_product_sales_report {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string category;
};

struct Sale {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
