  struct Product {
    sqlgen::PrimaryKey<int> product_id;
    std::string sku;
    std::string name;
    std::string category;
    double price;
  };

  bool manage_indexes() {
    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      return false;
    }
    auto conn = *conn_result;

    // Create standard index on category with IF NOT EXISTS
    auto category_index = sqlgen::create_index<"idx_product_category", Product>("category"_c);
    category_index.if_not_exists_ = true;

    // Create unique index on sku with IF NOT EXISTS
    auto sku_index = sqlgen::create_index<"idx_product_sku", Product>("sku"_c);
    sku_index.unique_ = true;
    sku_index.if_not_exists_ = true;

    // Create composite index on (name, price) with IF NOT EXISTS
    auto name_price_index = sqlgen::create_index<"idx_product_name_price", Product>("name"_c, "price"_c);
    name_price_index.if_not_exists_ = true;

