    auto category_sql = conn->to_sql(transpilation::to_sql(category_index));
    auto sku_sql = conn->to_sql(transpilation::to_sql(sku_index));
    auto name_price_sql = conn->to_sql(transpilation::to_sql(name_price_index));

    return conn->execute(category_sql) && 
           conn->execute(sku_sql) && 
           conn->execute(name_price_sql);
  }

