#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into a temporary SQLite table, runs a query
 * to extract date/time parts and compute duration, and returns the results
 * as a vector of TemporalAnalysis.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data (const std::vector<Event>& events) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  const auto query =
      select_from<Event>(
          cast<int>("event_id"_c).as<"event_id">(), "event_name"_c, day("start_time"_c).as<"start_day">(),
          month("start_time"_c).as<"start_month">(),
          year("start_time"_c).as<"start_year">(),
          hour("start_time"_c).as<"start_hour">(),
          minute("start_time"_c).as<"start_minute">(),
          second("start_time"_c).as<"start_second">(),
          weekday("start_time"_c).as<"start_weekday">(),
          unixepoch("start_time"_c).as<"start_epoch">(),
          floor(days_between("start_time"_c, "end_time"_c)).as<"duration_days">()) |
      where("end_time"_c.is_not_null()) | to<std::vector<TemporalAnalysis>>;

  return sqlite::connect()
      .and_then(drop<Event> | if_exists)
      .and_then(create_table<Event>)
      .and_then(insert(events))
      .and_then(query)
      .value();
}

test cases:
#include <gtest/gtest.h>
#include <sqlgen/sqlite.hpp>
#include "analysis_temporal_data.hpp"

TEST(sqlite, AnalyzeTemporalData) {
  using Timestamp = sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">;

  std::vector<Event> events = {
      {1, "New Year Party", Timestamp("2023-01-01 20:00:00"), 
       Timestamp("2023-01-02 02:00:00"), Timestamp("2022-12-01 10:00:00")},
      {2, "Conference", Timestamp("2023-03-15 09:00:00"), 
       Timestamp("2023-03-17 17:00:00"), Timestamp("2023-01-15 10:00:00")},
      {3, "Meeting", Timestamp("2023-06-01 14:30:45"), 
       std::nullopt, Timestamp("2023-05-20 10:00:00")}
  };

  auto results = analyze_temporal_data(events);

  // Should only return 2 events because Meeting has null end_time
  ASSERT_EQ(results.size(), 2);

  // Verify New Year Party
  const auto& party = results[0];
  EXPECT_EQ(party.event_id, 1);
  EXPECT_EQ(party.event_name, "New Year Party");
  EXPECT_EQ(party.start_day, 1);
  EXPECT_EQ(party.start_month, 1);
  EXPECT_EQ(party.start_year, 2023);
  EXPECT_EQ(party.start_hour, 20);
  EXPECT_EQ(party.start_minute, 0);
  EXPECT_EQ(party.start_second, 0);
  // 2023-01-01 was a Sunday (0)
  EXPECT_EQ(party.start_weekday, 0); 
  // Unix epoch for 2023-01-01 20:00:00 UTC
  EXPECT_GT(party.start_epoch, 0);

  // Duration: 20:00 to 02:00 next day is < 1 day, so 0 days
  EXPECT_EQ(party.duration_days, 0);

  // Verify Conference
  const auto& conference = results[1];
  EXPECT_EQ(conference.event_id, 2);
  EXPECT_EQ(conference.event_name, "Conference");
  EXPECT_EQ(conference.start_day, 15);
  EXPECT_EQ(conference.start_month, 3);
  EXPECT_EQ(conference.start_year, 2023);
  // 2023-03-15 was a Wednesday (3)
  EXPECT_EQ(conference.start_weekday, 3);

  // Duration: March 15 to March 17 is 2 days
  EXPECT_EQ(conference.duration_days, 2);
}

