  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Perform upsert operation
  auto write_result = sqlgen::write(conn, items, true);
  if (!write_result) {
    return false;
  }

  // Read back the items to verify
  auto read_result = sqlgen::read<std::vector<Inventory>>(conn);
  if (!read_result) {
    return false;
  }
  auto read_items = read_result.value();

  // Compare original items with read items
  // Sort both vectors by item_id to ensure consistent comparison
  std::vector<Inventory> sorted_original = items;
  std::sort(sorted_original.begin(), sorted_original.end(),
              [](const Inventory& a, const Inventory& b) {
                return a.item_id < b.item_id;
              });

  std::vector<Inventory> sorted_read = read_items;
  std::sort(sorted_read.begin(), sorted_read.end(),
              [](const Inventory& a, const Inventory& b) {
                return a.item_id < b.item_id;
              });

  // Verify all fields match
  if (sorted_original.size() != sorted_read.size()) {
    return false;
