  for (size_t i = 0; i < sorted_original.size(); ++i) {
    if (sorted_original[i].item_id != sorted_read[i].item_id ||
        sorted_original[i].name != sorted_read[i].name ||
        sorted_original[i].quantity != sorted_read[i].quantity) {
      return false;
    }
  }

  return true;
}

}  // namespace upsert_inventory_items
