```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <algorithm>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::string city;
};

struct Friendship {
  int user_id1;
  int user_id2;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;
  sqlgen::Unique<sqlgen::PrimaryKey<std::tuple<int, int>>> primary_key;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
  int mutual_count;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Create in-memory database connection
  auto conn_result = sqlgen::sqlite::connect(":memory:");
  if (!conn_result) {
    return {};
  }
  auto conn = conn_result.value();

  // Create tables
  auto create_user_table = CreateTable<User>{};
  auto create_friendship_table = CreateTable<Friendship>{};

  conn | create_user_table;
  conn | create_friendship_table;

  // Insert data
  if (!users.empty()) {
    conn | insert(users);
  }
  if (!friendships.empty()) {
    conn | insert(friendships);
  }

  // Query 1: Mutual friends using SELF-JOIN
  auto mutual_query = select_from<User, "u1">("username"_t1 | as<"user1_name">, 
                                             "username"_t2 | as<"user2_name">)
    | inner_join<Friendship, "f1">("user_id1"_t1 == "user_id"_t1 && "user_id2"_t1 == "user_id"_t2)
    | inner_join<User, "u2">("user_id"_t2 == "user_id2"_t1)
    | where("user_id"_t1 < "user_id"_t2)
    | group_by("user_id"_t1, "user_id"_t2)
    | having(count() > 0);

  auto mutual_results = mutual_query(conn);

  // Query 2: Users with more than average friends using nested query
  auto avg_friends_subquery = select_from<Friendship>(count().as<"friend_count">)
    | group_by("user_id1");

  auto above_avg_query = select_from<User>("user_id"_t1 | as<"user_id">, "username"_t1 | as<"username">)
    | left_join<Friendship, "f">(col<"user_id">_t1 == "user_id1"_t2)
    | group_by("user_id"_t1)
    | having(count() > avg_friends_subquery);

  auto above_avg_results = above_avg_query(conn);

  // Query 3: Friend-of-friend relationships
  auto friend_of_friend_query = select_from<User, "u1">("username"_t1 | as<"user1_name">, 
                                                        "username"_t2 | as<"user2_name">)
    | inner_join<Friendship, "f1">("user_id1"_t1 == "user_id1"_t1)
    | inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t2)
    | inner_join<User, "u2">("user_id2"_t2 == "user_id"_t2)
    | where("user_id"_t1 != "user_id"_t2);

  auto friend_of_friend_results = friend_of_friend_query(conn);

  // Query 4: Most connected users
  auto most_connected_query = select_from<User>("user_id"_t1 | as<"user_id">, 
                                               "username"_t1 | as<"username">, 
                                               count().as<"friend_count">)
    | left_join<Friendship, "f">(col<"user_id">_t1 == "user_id1"_t2 || col<"user_id">_t1 == "user_id2"_t2)
    | group_by("user_id"_t1)
    | order_by(count().desc());

  auto most_connected_results = most_connected_query(conn);

  // Query 5: Same city recommendations
  auto recommendations_query = select_from<User, "u1">("username"_t1 | as<"user1_name">, 
                                                      "username"_t2 | as<"user2_name">)
    | inner_join<User, "u2">("city"_t1 == "city"_t2 && "user_id"_t1 < "user_id"_t2)
    | where(!exists(select_from<Friendship>("user_id1"_t3 == "user_id"_t1 && "user_id2"_t3 == "user_id"_t2)));

  auto recommendations_results = recommendations_query(conn);

  // Combine all results
  std::vector<FriendConnection> results;

  // Process mutual friends
  for (const auto& row : mutual_results) {
    results.push_back(FriendConnection{
        .user1_name = row.template get_field<"user1_name">(),
        .user2_name = row.template get_field<"user2_name">(),
        .mutual_count = 1
    });
  }

  // Process friend-of-friend relationships
  for (const auto& row : friend_of_friend_results) {
    results.push_back(FriendConnection{
        .user1_name = row.template get_field<"user1_name">(),
        .user2_name = row.template get_field<"user2_name">(),
        .mutual_count = 0
    });
  }

  // Process recommendations
  for (const auto& row : recommendations_results) {
    results.push_back(FriendConnection{
        .user1_name = row.template get_field<"user1_name">(),
        .user2_name = row.template get_field<"user2_name">(),
        .mutual_count = -1 // Indicates recommendation
    });
  }

  return results;
}

}  // namespace analyze_social_network
```

**Key Implementation Details:**

1. **Database Connection**: Uses `sqlgen::sqlite::connect(":memory:")` to create an in-memory SQLite database
2. **Table Creation**: Uses `CreateTable<T>` with the defined User and Friendship structures
3. **Data Insertion**: Uses `insert()` function to populate tables with provided data
4. **SELF-JOIN Query**: Implements mutual friends detection using nested joins and WHERE conditions
5. **Nested Query**: Uses subquery to find users with above-average friend counts
6. **Complex Relationships**: Implements friend-of-friend detection with multiple joins
7. **Aggregation**: Uses COUNT() and AVG() functions for network statistics
8. **Recommendations**: Finds potential connections using NOT EXISTS clause

The implementation follows sqlgen's fluent API pattern using the `operator|` for method chaining and leverages the type-safe query building capabilities provided by the library.

