JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // 1. Connect to SQLite database
  auto conn = sqlgen::sqlite::connect(":memory:");

  // 2. Create tables
  conn | sqlgen::create_table<Department> | sqlgen::create_table<Employee>;

  // 3. Insert data
  conn | sqlgen::insert(depts) | sqlgen::insert(emps);

  // 4. Perform INNER JOIN
  auto inner_query = sqlgen::read<std::vector<JoinResult>> 
      | sqlgen::inner_join<Department, "d">("department_id"_d == "department_id"_e);
  auto inner_result = inner_query(conn);

  // 5. Perform LEFT JOIN
  auto left_query = sqlgen::read<std::vector<JoinResult>> 
      | sqlgen::left_join<Department, "d">("department_id"_d == "department_id"_e);
  auto left_result = left_query(conn);

  // 6. Perform RIGHT JOIN
  auto right_query = sqlgen::read<std::vector<JoinResult>> 
      | sqlgen::right_join<Department, "d">("department_id"_d == "department_id"_e);
  auto right_result = right_query(conn);

  // 7. Perform FULL JOIN
  auto full_query = sqlgen::read<std::vector<JoinResult>> 
      | sqlgen::full_join<Department, "d">("department_id"_d == "department_id"_e);
  auto full_result = full_query(conn);

  // 8. Return comprehensive analysis
  return JoinAnalysis{
      .inner_join_results = std::move(*inner_result),
      .left_join_results = std::move(*left_result),
      .right_join_results = std::move(*right_result),
      .full_join_results = std::move(*full_result)
  };
}
}  // namespace analyze_department_employees
```

